function criarTabelaDeListagem(config) {
    const container = '#tabela';
    const pk = (config.pk || 'id').toLowerCase();
    const colunas = config.colunas.map(c => String(c)).map(c => c.toLowerCase());
    const maxBotoesPaginacao = config.maxBotoesPaginacao || 5;
    
    // normaliza dados: transforma todas as keys para lowercase (para acesso consistente)
    let originalData = (config.data || []).map(item => {
        const normalizado = {};
        for (const k in item) {
            normalizado[String(k).toLowerCase()] = item[k];
        }
        return normalizado;
    });
    
    // estado
    let dadosFiltrados = originalData.slice();
    let paginaAtual = 1;
    let perPage = Number(config.itensPorPaginaDefault || 10);
    let sortCol = null; // coluna atual de ordenação (lowercase)
    let sortDir = 'asc'; // 'asc' ou 'desc'
    
    // utilitários
    function humanize(s) {
        return String(s).replace(/_/g,' ').split(' ')
        .map(w => w ? (w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()) : '')
        .join(' ');
    }
    function escapeHtml(str) {
        if (str == null) return '';
        return String(str).replace(/[&<>"'`=\/]/g, function(s) {
            return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;','/':'&#x2F;','`':'&#x60;','=':'&#x3D;'}[s]);
        });
    }
    function isNumeric(n) {
        if (n == null) return false;
        // aceita "10", "10.5", "-3.2"
        return !isNaN(parseFloat(String(n).replace(',', '.'))) && isFinite(n);
    }

    // monta layout inicial
    $(container).html(`
        <div class="tabela-filtros">
            <div class="form-container">
                <form class="form-wrap">
                    <label class="form form-m">
                        <div class="form-label">Filtrar</div>
                        <input type="text" id="tabela-filter" placeholder="Filtrar" class="form-input">
                    </label>
                    <label class="form form-m">
                        <div class="form-label">Registros por página</div>
                        <select class="form-input form-select" id="tabela-perPage">
                            <option value="5">5</option>
                            <option value="10">10</option>
                            <option value="20">20</option>
                        </select>
                    </label>
                    <div class="clear-both"></div>
                </form>
            </div>
        </div>
        <div class="overflow-hidden">
            <table class="tabela" id="tabela-table">
                <thead>
                    <tr>
                        ${colunas.filter(c => c !== 'ativo').map(c => `<th class="color-preto-1 font-weight-bold" data-col="${c}" style="cursor:pointer">${humanize(c)} <span class="sort-arrow"></span></th>`).join('')}
                        ${colunas.includes('ativo') ? `<th class="color-preto-1 font-weight-bold" data-col="ativo" style="cursor:pointer" width="60">Ativo <span class="sort-arrow"></span></th></th>` : ''}
                        <th class="color-preto-1 font-weight-bold" width="60">Ações</th>
                    </tr>
                </thead>
                <tbody></tbody>
            </table>
        </div>
        <div class="paginacao" id="tabela-pagination"></div>

        <div class="modal modal-confirmacao" id="modal-excluir">
            <div class="modal-wrap background-branco border-radius box-shadow">
                <button type="button" class="modal-fechar material-icon box-shadow" id="modal-excluir-fechar">close</button>
                
                <p class="modal-titulo color-preto-1">Confirmação de exclusão</p>
                
                <div class="modal-conteudo">
                    <p class="font-size-0875">Deseja realmente excluir este item?</p>
                    
                    <div class="form-button-group">
                        <button type="button" class="form-button background-cinza" id="modal-excluir-nao">Não</button>
                        <button type="button" class="form-button background-vermelho" id="modal-excluir-sim">Sim</button>
                    </div>
                </div>
            </div>
        </div>
    `);

    // define perPage no select
    $('#tabela-perPage').val(String(perPage));
    
    // lógica de ordenação
    function applySort() {
        if (!sortCol) return;
        dadosFiltrados.sort((a, b) => {
            let va = a[sortCol]; if (va == null) va = '';
            let vb = b[sortCol]; if (vb == null) vb = '';
            // tenta numérico primeiro
            if (isNumeric(va) && isNumeric(vb)) {
                const na = parseFloat(String(va).replace(',', '.'));
                const nb = parseFloat(String(vb).replace(',', '.'));
                return (na - nb) * (sortDir === 'asc' ? 1 : -1);
            }
            // fallback para string compare - usa Intl compare com numeric:true para "2" < "10" lógico
            return String(va).localeCompare(String(vb), undefined, { numeric: true, sensitivity: 'base' }) * (sortDir === 'asc' ? 1 : -1);
        });
    }

    // aplica filtro baseado no input (sobre os dados originais)
    function aplicarFiltros(filterText) {
        if (!filterText) {
            dadosFiltrados = originalData.slice();
            return;
        }
        const q = filterText.trim().toLowerCase();
        dadosFiltrados = originalData.filter(item => {
            // procura em todas as chaves do objeto
            for (const k in item) {
                const val = item[k];
                if (val != null && String(val).toLowerCase().indexOf(q) !== -1) return true;
            }
            return false;
        });
    }
    
    // render do corpo da tabela (apenas as linhas da página atual)
    function renderRows() {
        const $tbody = $(`${container} table tbody`);
        $tbody.empty();

        if (dadosFiltrados.length === 0) {
            $tbody.append(`<tr><td colspan="${colunas.length + 1}" class="no-data">Sem registros.</td></tr>`);
            $('#tabela-pagination').html('').addClass("display-none");
            updateSortArrows();
            return;
        }

        const total = dadosFiltrados.length;
        const totalPages = Math.max(1, Math.ceil(total / perPage));
        if (paginaAtual > totalPages) paginaAtual = totalPages;
        const start = (paginaAtual - 1) * perPage;
        const end = start + perPage;
        const pageData = dadosFiltrados.slice(start, end);

        const rowsHtml = pageData.map(item => {
            const idVal = item[pk] !== undefined ? item[pk] : '';

            // monta células exceto ativo
            const tds = colunas.filter(c => c !== 'ativo').map(col => `<td>${escapeHtml(item[col])}</td>`).join('');

            // ativo com switch
            let ativoTd = '';
            if (colunas.includes('ativo')) {
                const checked = (item['ativo'] == 1 || item['ativo'] === true) ? 'checked' : '';
                ativoTd = `<td>
                    <label class="switch">
                        <input type="checkbox" class="toggle-switch" data-id="${idVal}" ${checked}>
                        <span class="slider"></span>
                    </label>
                </td>`;
            }

            let deleteButtonHtml = ``;

            if (config.deleteUrl) {
                deleteButtonHtml = `<button type="button" class="delete-btn material-icon" data-id="${escapeHtml(idVal)}">delete</button>`;
            }

            return `<tr data-pk="${escapeHtml(idVal)}">
                        ${tds}
                        ${ativoTd}
                        <td>
                            <div class="tabela-buttons">
                                <button type="button" class="edit-btn material-icon" data-id="${escapeHtml(idVal)}">edit</button>
                                ${deleteButtonHtml}
                            </div>
                        </td>
                    </tr>`;
        }).join('');

        $tbody.html(rowsHtml);
        criaPaginacao();
        updateSortArrows();
    }
    
    // Renderiza a paginação (prev / jan window / next)
    function criaPaginacao() {
        const $pag = $('#tabela-pagination');
        $pag.empty();
        
        const total = dadosFiltrados.length;
        const paginas = Math.max(1, Math.ceil(total / perPage));

        if (paginas > 1) {
            // Prev
            const $prev = $(`<button class="paginacao-btn" id="paginacao-btn-prev" ${paginaAtual === 1 ? 'disabled' : ''}>«</button>`);
            $pag.append($prev);

            // Janela de páginas (max maxBotoesPaginacao)
            let start = Math.max(1, paginaAtual - Math.floor(maxBotoesPaginacao / 2));
            let end = Math.min(paginas, start + maxBotoesPaginacao - 1);
            if (end - start + 1 < maxBotoesPaginacao) start = Math.max(1, end - maxBotoesPaginacao + 1);

            for (let i = start; i <= end; i++) {
                const $b = $(`<button class="paginacao-btn" data-page="${i}">${i}</button>`);
                if (i === paginaAtual) $b.addClass('paginacao-btn-ativo');
                $pag.append($b);
            }

            // Next
            const $next = $(`<button class="paginacao-btn" id="paginacao-btn-next" ${paginaAtual === paginas ? 'disabled' : ''}>»</button>`);
            $pag.append($next);
            $pag.removeClass("display-none");
        }
        else {
            $pag.addClass("display-none");
        }
    }

    // atualiza setinhas do cabeçalho
    function updateSortArrows() {
        $(`${container} th .sort-arrow`).text('');
        if (sortCol) {
            const arrow = sortDir === 'asc' ? '▲' : '▼';
            $(`${container} th[data-col="${sortCol}"] .sort-arrow`).text(arrow);
        }
    }

    // atualiza tudo: aplica sort -> renderRows
    function atualizar() {
        applySort();
        renderRows();
    }

    // handlers (delegation)
    // filtro (enter ou digitação) - filtra os dados e volta para a página 1
    $(container).off('keyup', '#tabela-filter').on('keyup', '#tabela-filter', function(e) {
        paginaAtual = 1;
        const q = $(this).val();
        aplicarFiltros(q);
        atualizar();
    });

    // perPage change
    $(container).off('change', '#tabela-perPage').on('change', '#tabela-perPage', function() {
        perPage = parseInt($(this).val(), 10) || 10;
        paginaAtual = 1;
        atualizar();
    });

    // clique no header: ordena (toggle se for mesma coluna)
    $(container).off('click', 'th[data-col]').on('click', 'th[data-col]', function() {
        const col = $(this).data('col');
        if (sortCol === col) {
            sortDir = sortDir === 'asc' ? 'desc' : 'asc';
        } else {
            sortCol = col;
            sortDir = 'asc';
        }
        atualizar();
    });

    // paginação - delegada
    $(container).off('click', '.paginacao-btn').on('click', '.paginacao-btn', function() {
        const p = Number($(this).data('page'));
        if (!isNaN(p)) {
            paginaAtual = p;
            atualizar();
            // scroll top da tabela (opcional)
            // $('html, body').animate({ scrollTop: $(container).offset().top - 40 }, 150);
        }
    });

    $(container).off('click', '#paginacao-btn-prev').on('click', '#paginacao-btn-prev', function() {
        if (paginaAtual > 1) {
            paginaAtual--;
            atualizar();
        }
    });
    $(container).off('click', '#paginacao-btn-next').on('click', '#paginacao-btn-next', function() {
        const paginas = Math.max(1, Math.ceil(dadosFiltrados.length / perPage));
        if (paginaAtual < paginas) {
            paginaAtual++;
            atualizar();
        }
    });

    // Ações: edit / toggle / delete  (você pode substituir para AJAX)
    $(container).off('click', '.edit-btn').on('click', '.edit-btn', function() {
        const id = $(this).data('id');
        if (config.editUrl) {
            window.location.href = `${config.editUrl}?id=${encodeURIComponent(id)}`;
        } else if (typeof config.onEdit === 'function') {
            config.onEdit(id);
        } else {
            console.log('Editar:', id);
        }
    });

    // ATIVA e DESATIVA o item
    $(container).off('click', '.toggle-switch').on('click', '.toggle-switch', function() {
        const $this = $(this);
        const id = $this.data('id');
        // encontra item no originalData e alterna campo 'ativo'
        const item = originalData.find(it => String(it[pk]) === String(id));
        if (!item) return alert('Item não encontrado');
        // alterna (aceita 1/0, true/false)
        const current = item['ativo'] !== undefined ? item['ativo'] : 0;
        const newVal = (current === 1 || current === '1' || current === true) ? 0 : 1;
        
        $("body").addClass("loading");
        
        $.ajax({
            url: URL_REQUESTS + config.toggleUrl,
            method: "PUT",
            contentType: "application/json",
            headers: { "Authorization": "Bearer " + localStorage.getItem("refresh_token") },
            data: JSON.stringify({ id: id, ativo: newVal === 1 }),
            success: function(res) {
                item['ativo'] = newVal;
                aplicarFiltros($('#tabela-filter').val());
                atualizar();
                $this.prop('checked', newVal === 1);
            },
            error: function(res) {
                item['ativo'] = item['ativo'] ? 0 : 1;
                $this.prop('checked', item['ativo'] == 1);
                mostrarAlerta(res.responseJSON.error, "erro", 2, res.status);
            },
            complete: function(res) {
                $("body").removeClass("loading");
            }
        });
        
        // atualiza localmente
        item['ativo'] = newVal;
        aplicarFiltros($('#tabela-filter').val());
        atualizar();
    });
    
    $(container).off('click', '.delete-btn').on('click', '.delete-btn', function() {
        const id = $(this).data('id');
        
        $('#modal-excluir').addClass("modal-ativo");
        $('#modal-excluir-sim').attr('data-id', id);
    });

    // Funcionalidades da modal de exclusão
    $(container).off('click', '#modal-excluir-fechar').on('click', '#modal-excluir-fechar', function() {
        $("#modal-excluir").removeClass("modal-ativo");
    });
    $(container).off('click', '#modal-excluir-nao').on('click', '#modal-excluir-nao', function() {
        $("#modal-excluir").removeClass("modal-ativo");
    });
    $(container).off('click', '#modal-excluir-sim').on('click', '#modal-excluir-sim', function() {
        let id = $(this).attr('data-id');
        
        $("body").addClass("loading");
        
        $.ajax({
            url: URL_REQUESTS + config.deleteUrl,
            method: "DELETE",
            contentType: "application/json",
            headers: { "Authorization": "Bearer " + localStorage.getItem("refresh_token") },
            data: JSON.stringify({ id: id }),
            success: function(resp) {
                originalData = originalData.filter(it => String(it[pk]) !== String(id));
                aplicarFiltros($('#tabela-filter').val());
                atualizar();
                mostrarAlerta(config.tipoLista + " excluída com sucesso", "sucesso", 2);
            },
            error: function(res) {
                mostrarAlerta(res.responseJSON.error, "erro", 2, res.status);
            },
            complete: function(res) {
                $('#modal-excluir').removeClass("modal-ativo");
                $("body").removeClass("loading");
            }
        });
    });
    
    // inicializa filtro vazio e renderiza
    aplicarFiltros($('#tabela-filter').val());
    atualizar();
}